const inputItems = $input.all();
const deporte = inputItems[0].json.deporte;

if (deporte === 'todos') {
  const deportes = ['futbol', 'baloncesto', 'mlb', 'nhl', 'nfl', 'hipismo'];
  return deportes.map(d => ({ json: { deporte: d } }));
} else {
  return inputItems;
}

const fecha = new Date().toISOString().slice(0,10).replace(/-/g,'');
const ligas = [
  'eng.1', 'esp.1', 'ger.1', 'ita.1', 'fra.1',
  'uefa.champions', 'uefa.europa', 'concacaf.champions', 'bra.1',
  'ned.1', 'por.1', 'tur.1', 'arg.1', 'mex.1',
  'usa.1', 'sco.1', 'bel.1', 'aut.1', 'sui.1',
  'den.1', 'gre.1'
];
return ligas.map(liga => ({
  json: { url: `https://site.api.espn.com/apis/site/v2/sports/soccer/${liga}/scoreboard?dates=${fecha}` }
}));

const items = $input.all();
const allEvents = [];

for (const item of items) {
  if (item.json && item.json.events && Array.isArray(item.json.events)) {
    allEvents.push(...item.json.events);
  }
}

return [{ json: { events: allEvents } }];

const data = $input.all()[0].json;
let outputText = '';
let noGames = false;

if (data.events && Array.isArray(data.events)) {
  const events = data.events;
  if (events.length === 0) {
    noGames = true;
    outputText = '⚠️ NO HAY PARTIDOS PROGRAMADOS PARA HOY';
  } else {
    outputText = `PARTIDOS DE FÚTBOL DEL DÍA (${new Date().toLocaleDateString('es-ES')})\n`;
    outputText += '='.repeat(50) + '\n';

    events.forEach((event, index) => {
      const competition = event.competitions?.[0];
      if (competition) {
        const homeTeam = competition.competitors?.find(c => c.homeAway === 'home')?.team?.displayName || 'Desconocido';
        const awayTeam = competition.competitors?.find(c => c.homeAway === 'away')?.team?.displayName || 'Desconocido';
        const homeRecord = competition.competitors?.find(c => c.homeAway === 'home')?.records?.[0]?.summary || 'N/D';
        const awayRecord = competition.competitors?.find(c => c.homeAway === 'away')?.records?.[0]?.summary || 'N/D';
        const status = competition.status?.type?.name || 'Programado';
        const startDate = competition.startDate ? new Date(competition.startDate).toLocaleString('es-ES') : 'Hora no disponible';

        outputText += `${index + 1}. ${awayTeam} (${awayRecord}) @ ${homeTeam} (${homeRecord})\n`;
        outputText += `   Estado: ${status}\n`;
        outputText += `   Fecha/Hora: ${startDate}\n`;
        outputText += '-'.repeat(30) + '\n';
      }
    });
  }
} else {
  noGames = true;
  outputText = '⚠️ NO HAY PARTIDOS PROGRAMADOS PARA HOY';
}

return [{ json: { texto_partidos: outputText, no_games: noGames } }];

const html = $input.first().json.data;

// 1. Eliminar scripts, estilos y comentarios
let cleaned = html
  .replace(/<script\b[^<]*(?:(?!<\/script>)<[^<]*)*<\/script>/gi, ' ')
  .replace(/<style\b[^<]*(?:(?!<\/style>)<[^<]*)*<\/style>/gi, ' ')
  .replace(/<!--[\s\S]*?-->/g, ' ')
  .replace(/<[^>]+>/g, ' ');

// 2. Decodificar entidades HTML comunes
cleaned = cleaned.replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&[a-z]+;/g, ' ');

// 3. Colapsar espacios
cleaned = cleaned.replace(/\s+/g, ' ').trim();

// 4. Extraer líneas que contengan palabras clave de carreras
const lines = cleaned.split(/\s*\.\s*/);
const keywords = /(carrera|distancia|ejemplar|jinete|stud|ganador|dividendo|importado|nacional|favorito|hipódromo)/i;
const relevant = lines.filter(line => keywords.test(line));

let resumen = relevant.length > 0 ? relevant.join('. ') : cleaned.substring(0, 6000);

// Limitar a 6000 caracteres para no sobrecargar la IA
resumen = resumen.substring(0, 6000);

return [{ json: { resumen: resumen } }];

